**Issue:** Boundary condition at 30-second skew causes refresh loops when `expMs - nowMs ≤ 30000`.

**Fix:**
```javascript
if (expMs + 30000 < nowMs) return 401;
```

**Test:**
```javascript
// Edge case: exactly at 30s skew
assert(auth_mw(nowMs - expMs === 30000) !== 401);
assert(auth_mw(nowMs - expMs === 30001) === 401);
```

This prevents 401s within the 30-second grace period and stops premature token refreshes.

```javascript
async function loadUser(req, res, next) {
  if (!req.params.id) {
    return res.status(400).json({ error: 'Missing user ID' });
  }

  try {
    const user = await db.findUser(req.params.id);
    if (!user) {
      return res.status(404).json({ error: 'User not found' });
    }

    await audit.log('user_accessed', { userId: req.params.id });
    await cache.set(`user:${req.params.id}`, user);

    res.json(user);
  } catch (err) {
    next(err);
  }
}
```

